const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const result = $('Save Link').item.json;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let text;
if (result.duplicate) {
  text = '⚠️ Already saved this link before';
} else {
  text = `✅ Saved to ${result.category}\n\n📌 ${result.title}\n${result.summary}\n\n🏷 ${result.tags}`;
}

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
  headers: { 'Content-Type': 'application/json' },
  body: {
    chat_id: chatId,
    text: text
  }
});

return { sent: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

// Line 4: Parse URL and personal note from message
const fullText = $('Telegram Trigger').item.json.message.text.trim();
const urlMatch = fullText.match(/https?:\/\/[^\s]+/);
if (!urlMatch) return [];
const originalUrl = urlMatch[0];
const rawNote = fullText.replace(originalUrl, '').trim();

// Line 10: Detect reminder instruction
const remindMatch = rawNote.match(/\/remind\s+(\d+)(day|days|week|weeks|month|months)/i);
let reminderDate = null;
let personalNote = rawNote.replace(/\/remind\s+\S+/i, '').trim();

if (remindMatch) {
  const amount = parseInt(remindMatch[1]);
  const unit = remindMatch[2].toLowerCase();
  const d = new Date();
  if (unit.startsWith('day')) d.setDate(d.getDate() + amount);
  else if (unit.startsWith('week')) d.setDate(d.getDate() + amount * 7);
  else if (unit.startsWith('month')) d.setMonth(d.getMonth() + amount);
  reminderDate = d.toISOString().split('T')[0];
}

// Line 23: Declare variables
let pageContent = '';
const videoPatterns = ['tiktok.com', 'youtube.com', 'youtu.be', 'instagram.com'];
const isVideo = videoPatterns.some(p => originalUrl.includes(p));
const isTelegram = originalUrl.includes('t.me/');
const isTwitter = originalUrl.includes('x.com') || originalUrl.includes('twitter.com');

// Line 29: Step 0 - Use yt-dlp API for video links
if (isVideo) {
  try {
    const ytResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: config.ytdlp_api_url + '/' + encodeURIComponent(originalUrl),
      timeout: 35000
    });
    pageContent = ytResponse.content || '';
  } catch(e) {
    pageContent = '';
  }
}
// Line 39: Detect Reddit links
const isReddit = originalUrl.includes('reddit.com') || originalUrl.includes('redd.it');
// Line 40: Step 0b - Fetch X.com post via oEmbed
if (isTwitter) {
  try {
    const oembedResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://publish.twitter.com/oembed?url=' + encodeURIComponent(originalUrl) + '&omit_script=true',
      timeout: 10000
    });
    const html = oembedResponse.html || '';
    pageContent = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
    if (oembedResponse.author_name) {
      pageContent = 'Author: ' + oembedResponse.author_name + ' | ' + pageContent;
    }
  } catch(e) {
    pageContent = 'X.com post — could not fetch content.';
  }
}
// Step 0c - Extract Reddit info from URL
if (isReddit && !pageContent) {
  const subredditMatch = originalUrl.match(/reddit\.com\/r\/([^\/]+)/);
  const slugMatch = originalUrl.match(/comments\/[^\/]+\/([^\/\?]+)/);
  const subreddit = subredditMatch ? subredditMatch[1] : '';
  const slug = slugMatch ? slugMatch[1].replace(/_/g, ' ') : '';
  pageContent = 'Reddit post' + 
    (subreddit ? ' in r/' + subreddit : '') + 
    (slug ? ': ' + slug : '') +
    '. URL: ' + originalUrl;
}
// Line 54: Step 0c - Fetch Telegram post content via Bot API
if (isTelegram) {
  try {
    const tgMatch = originalUrl.match(/t\.me\/(?:c\/)?([^\/]+)\/(\d+)/);
    if (tgMatch) {
      const chatId = tgMatch[1].startsWith('c/') ? '-100' + tgMatch[1] : '@' + tgMatch[1];
      const messageId = tgMatch[2];
      const tgResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/forwardMessage',
        body: {
          chat_id: config.telegram_chat_id,
          from_chat_id: chatId,
          message_id: parseInt(messageId)
        }
      });
      pageContent = tgResponse?.result?.text || tgResponse?.result?.caption || '';
    }
  } catch(e) {
    pageContent = '';
  }
}

// Line 74: Step 1 - Fetch page content via Firecrawl
if (!isVideo && !isTelegram && !isTwitter && !isReddit) {
  try {
    const crawlResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.firecrawl.dev/v1/scrape',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + config.firecrawl_api_key
      },
      body: {
        url: originalUrl,
        formats: ['markdown'],
        onlyMainContent: true
      },
      timeout: 30000
    });
    const content = crawlResponse?.data?.markdown || crawlResponse?.markdown || '';
    pageContent = content.slice(0, 3000);
  } catch(e) {
    pageContent = 'Could not fetch page. URL: ' + originalUrl;
  }
}

// Line 95: Check for duplicates
try {
  const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
  for (const file of files) {
    const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
    if (content.includes(originalUrl)) {
      return {
        success: false,
        duplicate: true,
        message: 'Already saved this link before'
      };
    }
  }
} catch(e) {}

// Line 107: Step 2 - Ask Groq to analyze
const groqResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + config.groq_api_key
  },
  body: {
    model: 'llama-3.3-70b-versatile',
    temperature: 0.1,
    messages: [
      {
        role: 'system',
        content: 'You are a personal knowledge capture assistant. Analyze web content and return structured JSON only. No markdown, no explanation, no code blocks. Just raw JSON.'
      },
      {
        role: 'user',
        content: 'Analyze this link.\n\nURL: ' + originalUrl + '\nMy personal note: ' + (personalNote || 'none') + '\nPage content: ' + pageContent + '\n\nReturn a JSON object with:\n- title: clear descriptive title\n- summary: 2-3 sentence summary of what this is and why someone saved it\n- tags: array of 3-5 specific relevant tags (lowercase, underscores for spaces e.g. prompt_engineering, saudi_food)\n- category: single lowercase word that best describes the topic (e.g. ai, travel, cooking, finance, fitness, design, productivity, tech, shopping, health, education)\n\nReturn only the JSON object, nothing else.'
      }
    ]
  }
});

// Line 132: Step 3 - Parse response
const raw = groqResponse.choices?.[0]?.message?.content || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { title: 'Saved link', summary: originalUrl, tags: ['general'], category: 'general' };
}

// Line 142: Step 4 - Sanitize and build entry
const category = (parsed.category || 'general').toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 20) || 'general';
const tags = (parsed.tags || ['general']).map(t => '#' + t.toLowerCase().replace(/[\s-]+/g, '_')).join(' ');
const date = new Date().toISOString().split('T')[0];
const noteSection = personalNote ? '\n**My note:** ' + personalNote + '\n' : '';
const reminderSection = reminderDate ? '\n**Reminder:** ' + reminderDate + '\n' : '';
const entry = '\n## [' + parsed.title + '](' + originalUrl + ')\n**Saved:** ' + date + '\n**Tags:** ' + tags + '\n> ' + parsed.summary + '\n' + noteSection + reminderSection + '\n---\n';

// Line 149: Step 5 - Write to file
const dir = config.knowledge_dir;
const filepath = dir + '/' + category + '.md';
fs.mkdirSync(dir, { recursive: true });
if (!fs.existsSync(filepath)) {
  fs.writeFileSync(filepath, '# ' + category + '\n', 'utf8');
}
fs.appendFileSync(filepath, entry, 'utf8');

return {
  success: true,
  category,
  title: parsed.title,
  summary: parsed.summary,
  tags,
  url: originalUrl
};

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const message = $('Telegram Trigger').item.json.message;
if (!message.voice && !message.audio) return [];

const fileId = message.voice?.file_id || message.audio?.file_id;
const chatId = message.chat.id;

// Step 1: Get file path from Telegram
const fileInfo = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/getFile?file_id=' + fileId
});
const filePath = fileInfo.result.file_path;
const fileUrl = 'https://api.telegram.org/file/bot' + config.telegram_bot_token + '/' + filePath;

// Step 2: Send to local Whisper API
const result = await this.helpers.httpRequest({
  method: 'POST',
  url: config.whisper_api_url,
  headers: { 'Content-Type': 'application/json' },
  body: {
    url: fileUrl,
    key: config.groq_api_key
  }
});

const text = result.text || '';

// Step 3: Detect reminder in transcribed text
const date = new Date().toISOString().split('T')[0];
const remindMatch = text.match(/\/remind\s+(\d+)(day|days|week|weeks|month|months)/i);
let reminderDate = null;
let cleanText = text.replace(/\/remind\s+\S+/i, '').trim();

if (remindMatch) {
  const amount = parseInt(remindMatch[1]);
  const unit = remindMatch[2].toLowerCase();
  const d = new Date();
  if (unit.startsWith('day')) d.setDate(d.getDate() + amount);
  else if (unit.startsWith('week')) d.setDate(d.getDate() + amount * 7);
  else if (unit.startsWith('month')) d.setMonth(d.getMonth() + amount);
  reminderDate = d.toISOString().split('T')[0];
}

// Step 4: Save to voice.md
const reminderSection = reminderDate ? '\n**Reminder:** ' + reminderDate + '\n' : '';
const entry = '\n## 🎤 Voice note — ' + date + '\n> ' + cleanText + '\n' + reminderSection + '\n---\n';

fs.mkdirSync(config.knowledge_dir, { recursive: true });
fs.appendFileSync(config.knowledge_dir + '/voice.md', entry, 'utf8');

return { chatId, text: cleanText, saved: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const chatId = $('Transcribe voice').item.json.chatId;
const text = $('Transcribe voice').item.json.text;

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
  headers: { 'Content-Type': 'application/json' },
  body: {
    chat_id: chatId,
    text: '🎤 Voice note saved\n\n📝 ' + text.slice(0, 4096)
  }
});

return { sent: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const message = $('Telegram Trigger').item.json.message;
if (!message.photo && !message.document?.mime_type?.startsWith('image')) return [];

const chatId = message.chat.id;
const caption = message.caption || '';

// Step 1: Get the largest photo size
const photo = message.photo
  ? message.photo[message.photo.length - 1]
  : message.document;
const fileId = photo.file_id;

// Step 2: Get file path from Telegram
const fileInfo = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/getFile?file_id=' + fileId
});
const filePath = fileInfo.result.file_path;
const fileUrl = 'https://api.telegram.org/file/bot' + config.telegram_bot_token + '/' + filePath;

// Step 3: Download image and convert to base64
const imageBuffer = await this.helpers.httpRequest({
  method: 'GET',
  url: fileUrl,
  returnFullResponse: true,
  encoding: 'arraybuffer'
});
const base64Image = Buffer.from(imageBuffer.body).toString('base64');
const mimeType = filePath.endsWith('.png') ? 'image/png' : 'image/jpeg';

// Step 4: Ask Groq vision to analyze the image
const groqResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + config.groq_api_key
  },
  body: {
    model: 'meta-llama/llama-4-scout-17b-16e-instruct',
    temperature: 0.1,
    messages: [
      {
        role: 'user',
        content: [
          {
            type: 'image_url',
            image_url: {
              url: 'data:' + mimeType + ';base64,' + base64Image
            }
          },
          {
            type: 'text',
            text: 'Analyze this image and return ONLY a raw JSON object, no markdown, no explanation.\n\nUser caption: ' + (caption || 'none') + '\n\nReturn exactly:\n{"title": "descriptive title", "summary": "2-3 sentence description of what this image shows and why someone saved it", "tags": ["tag1", "tag2", "tag3"], "category": "single lowercase word: travel, home, shopping, tech, fitness, food, design, inspiration, document, or other relevant word"}'
          }
        ]
      }
    ]
  }
});

// Step 5: Parse response
const raw = groqResponse.choices?.[0]?.message?.content || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { title: 'Saved image', summary: caption || 'An image', tags: ['image'], category: 'misc' };
}

// Step 6: Detect reminder in caption
const remindMatch = caption.match(/\/remind\s+(\d+)(day|days|week|weeks|month|months)/i);
let reminderDate = null;
const cleanCaption = caption.replace(/\/remind\s+\S+/i, '').trim();

if (remindMatch) {
  const amount = parseInt(remindMatch[1]);
  const unit = remindMatch[2].toLowerCase();
  const d = new Date();
  if (unit.startsWith('day')) d.setDate(d.getDate() + amount);
  else if (unit.startsWith('week')) d.setDate(d.getDate() + amount * 7);
  else if (unit.startsWith('month')) d.setMonth(d.getMonth() + amount);
  reminderDate = d.toISOString().split('T')[0];
}

// Step 7: Build entry and save
const date = new Date().toISOString().split('T')[0];
const timestamp = Date.now();
const category = (parsed.category || 'misc').toLowerCase().replace(/[^a-z0-9]/g, '');
const tags = (parsed.tags || ['image']).map(t => '#' + t.toLowerCase().replace(/[\s-]+/g, '_')).join(' ');

const imagesDir = config.knowledge_dir + '/images';
fs.mkdirSync(imagesDir, { recursive: true });
const imageFilename = timestamp + '.' + (filePath.endsWith('.png') ? 'png' : 'jpg');
fs.writeFileSync(imagesDir + '/' + imageFilename, Buffer.from(imageBuffer.body));

const reminderSection = reminderDate ? '\n**Reminder:** ' + reminderDate + '\n' : '';
const entry = '\n## 🖼 ' + parsed.title + '\n**Saved:** ' + date + '\n**Tags:** ' + tags + '\n**Image:** ' + imageFilename + '\n' + (cleanCaption ? '**Caption:** ' + cleanCaption + '\n' : '') + '> ' + parsed.summary + '\n' + reminderSection + '\n---\n';

const categoryFilepath = config.knowledge_dir + '/' + category + '.md';
if (!fs.existsSync(categoryFilepath)) {
  fs.writeFileSync(categoryFilepath, '# ' + category + '\n', 'utf8');
}
fs.appendFileSync(categoryFilepath, entry, 'utf8');

return { chatId, category, title: parsed.title, summary: parsed.summary, tags, saved: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const result = $('Save image').item.json;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + config.telegram_bot_token + '/sendMessage',
