return { sent: true };

const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const message = $('Telegram Trigger').item.json.message;
if (!message || !message.text) return [];
const question = message.text.trim();
const senderId = String(message.from?.id || '');

// ============================================
// Guest access helpers
// ============================================
function loadGuests() {
  try { return JSON.parse(fs.readFileSync(config.guests_file, 'utf8')); } catch(e) { return []; }
}
function saveGuests(guests) {
  fs.writeFileSync(config.guests_file, JSON.stringify(guests, null, 2), 'utf8');
}
function isOwner() {
  return senderId === String(config.telegram_chat_id);
}
function getGuest() {
  const guests = loadGuests();
  const today = new Date().toISOString().split('T')[0];
  return guests.find(g => String(g.telegram_id) === senderId && g.expires >= today) || null;
}

// ============================================
// Owner-only commands
// ============================================
if (isOwner()) {

  if (question.startsWith('http')) return [];

  // /invite command
  if (question.toLowerCase().startsWith('/invite')) {
    const parts = question.split(' ');
    if (parts.length < 4) {
      return { answer: 'Usage: /invite <telegram_id> <categories> <duration>\nExample: /invite 123456789 travel,food 7days\nDuration: 1day, 7days, 30days, permanent' };
    }
    const guestId = parts[1];
    const categories = parts[2].toLowerCase().split(',').map(c => c.trim().replace(/[^a-z0-9]/g, ''));
    const durationStr = parts[3].toLowerCase();
    let expires;
    if (durationStr === 'permanent') {
      expires = '9999-12-31';
    } else {
      const amount = parseInt(durationStr);
      const unit = durationStr.replace(/[0-9]/g, '');
      const d = new Date();
      if (unit.startsWith('day')) d.setDate(d.getDate() + amount);
      else if (unit.startsWith('week')) d.setDate(d.getDate() + amount * 7);
      else if (unit.startsWith('month')) d.setMonth(d.getMonth() + amount);
      expires = d.toISOString().split('T')[0];
    }
    const guests = loadGuests();
    const existingIdx = guests.findIndex(g => String(g.telegram_id) === guestId);
    const newGuest = { telegram_id: guestId, categories, expires, added: new Date().toISOString().split('T')[0] };
    if (existingIdx >= 0) guests[existingIdx] = newGuest; else guests.push(newGuest);
    saveGuests(guests);
    return { answer: '✅ Guest access granted\n\nID: ' + guestId + '\nCategories: ' + categories.join(', ') + '\nExpires: ' + expires };
  }

  // /guests command
  if (question.toLowerCase().startsWith('/guests')) {
    const guests = loadGuests();
    const today = new Date().toISOString().split('T')[0];
    const active = guests.filter(g => g.expires >= today);
    if (active.length === 0) return { answer: 'No active guests.' };
    const list = active.map((g, i) =>
      `${i + 1}. ID: ${g.telegram_id}\n   Categories: ${g.categories.join(', ')}\n   Expires: ${g.expires}`
    ).join('\n\n');
    return { answer: '👥 Active guests (' + active.length + '):\n\n' + list };
  }

  // /revoke command
  if (question.toLowerCase().startsWith('/revoke')) {
    const guestId = question.split(' ')[1];
    if (!guestId) return { answer: 'Usage: /revoke <telegram_id>' };
    let guests = loadGuests();
    const before = guests.length;
    guests = guests.filter(g => String(g.telegram_id) !== guestId);
    saveGuests(guests);
    return { answer: before > guests.length ? '✅ Access revoked for ' + guestId : '❌ Guest not found: ' + guestId };
  }

  // /list command
  if (question.toLowerCase().startsWith('/list') || question.toLowerCase().startsWith('list ')) {
    const listCategory = question.toLowerCase().replace(/^\/?list\s+/, '').replace(/[^a-z0-9]/g, '');
    if (!listCategory) return { answer: 'Usage: /list <category>\nExample: /list travel' };
    const filepath = config.knowledge_dir + '/' + listCategory + '.md';
    try {
      const content = fs.readFileSync(filepath, 'utf8');
      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));
      if (entries.length === 0) return { answer: 'No saved links in category: ' + listCategory };
      const list = entries.map((e, i) => {
        const titleMatch = e.match(/## \[(.+?)\]\((.+?)\)/);
        const dateMatch = e.match(/\*\*Saved:\*\* (.+)/);
        if (titleMatch) return `${i + 1}. ${titleMatch[1]}\n${titleMatch[2]}\n📅 ${dateMatch?.[1] || ''}`;
        return null;
      }).filter(Boolean).join('\n\n');
      return { answer: `📂 ${listCategory} — ${entries.length} saved links\n\n${list}` };
    } catch(e) {
      return { answer: 'No saved links in category: ' + listCategory };
    }
  }

  // /tag command
  if (question.toLowerCase().startsWith('/tag')) {
    const urlMatch = question.match(/https?:\/\/[^\s]+/);
    const tagMatches = question.match(/#[\w_]+/g);
    if (!urlMatch) return { answer: 'Usage: /tag <url> #tag1 #tag2' };
    const targetUrl = urlMatch[0];
    const userTags = tagMatches ? tagMatches.join(' ') : '';
    try {
      const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
      for (const file of files) {
        const filepath = config.knowledge_dir + '/' + file;
        let content = fs.readFileSync(filepath, 'utf8');
        if (content.includes(targetUrl)) {
          if (userTags) {
            content = content.replace(
              /(## \[.+?\]\(.+?\)[\s\S]*?\*\*Tags:\*\* )([^\n]+)/,
              (match, prefix, existingTags) => {
                const existing = existingTags.trim();
                const newTagsToAdd = (tagMatches || []).filter(t => !existing.includes(t)).join(' ');
                return prefix + existing + (newTagsToAdd ? ' ' + newTagsToAdd : '');
              }
            );
            fs.writeFileSync(filepath, content, 'utf8');
          }
          return { answer: '✅ Tags added to existing entry: ' + userTags };
        }
      }
    } catch(e) {}
    let pageContent = '';
    const isVideo = ['tiktok.com','youtube.com','youtu.be','instagram.com'].some(p => targetUrl.includes(p));
    const isTwitter = targetUrl.includes('x.com') || targetUrl.includes('twitter.com');
    if (isVideo) {
      try {
        const ytResponse = await this.helpers.httpRequest({ method: 'GET', url: config.ytdlp_api_url + '/' + encodeURIComponent(targetUrl), timeout: 35000 });
        pageContent = ytResponse.content || '';
      } catch(e) {}
    } else if (isTwitter) {
      try {
        const oembedResponse = await this.helpers.httpRequest({ method: 'GET', url: 'https://publish.twitter.com/oembed?url=' + encodeURIComponent(targetUrl) + '&omit_script=true', timeout: 10000 });
        const html = oembedResponse.html || '';
        pageContent = html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
        if (oembedResponse.author_name) pageContent = 'Author: ' + oembedResponse.author_name + ' | ' + pageContent;
      } catch(e) {}
    } else {
      try {
        const crawlResponse = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.firecrawl.dev/v1/scrape', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.firecrawl_api_key }, body: { url: targetUrl, formats: ['markdown'], onlyMainContent: true }, timeout: 30000 });
        pageContent = (crawlResponse?.data?.markdown || '').slice(0, 3000);
      } catch(e) { pageContent = 'Could not fetch page.'; }
    }
    const tagGroqResponse = await this.helpers.httpRequest({
      method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.groq_api_key },
      body: { model: 'llama-3.3-70b-versatile', temperature: 0.1, messages: [
        { role: 'system', content: 'You are a personal knowledge capture assistant. Return structured JSON only.' },
        { role: 'user', content: 'Analyze this link.\n\nURL: ' + targetUrl + '\nUser tags: ' + userTags + '\nPage content: ' + pageContent + '\n\nReturn JSON:\n{"title": "descriptive title", "summary": "2-3 sentence summary", "tags": ["tag1", "tag2", "tag3"], "category": "single lowercase word"}' }
      ]}
    });
    const tagRaw = tagGroqResponse.choices?.[0]?.message?.content || '';
    let tagParsed;
    try { const match = tagRaw.match(/\{[\s\S]*\}/); tagParsed = JSON.parse(match ? match[0] : tagRaw); }
    catch(e) { tagParsed = { title: 'Saved link', summary: targetUrl, tags: [], category: 'misc' }; }
    const tagCategory = (tagParsed.category || 'misc').toLowerCase().replace(/[^a-z0-9]/g, '') || 'misc';
    const groqTags = (tagParsed.tags || []).map(t => '#' + t.toLowerCase().replace(/[\s-]+/g, '_'));
    const allTags = [...new Set([...(tagMatches || []), ...groqTags])].join(' ');
    const tagDate = new Date().toISOString().split('T')[0];
    const tagEntry = '\n## [' + tagParsed.title + '](' + targetUrl + ')\n**Saved:** ' + tagDate + '\n**Tags:** ' + allTags + '\n> ' + tagParsed.summary + '\n\n---\n';
    const tagFilepath = config.knowledge_dir + '/' + tagCategory + '.md';
    if (!fs.existsSync(tagFilepath)) fs.writeFileSync(tagFilepath, '# ' + tagCategory + '\n', 'utf8');
    fs.appendFileSync(tagFilepath, tagEntry, 'utf8');
    return { answer: '✅ Saved to ' + tagCategory + ' with tags: ' + allTags + '\n\n📌 ' + tagParsed.title + '\n' + tagParsed.summary };
  }

  // /rules command
  if (question.toLowerCase().startsWith('/rules')) {
    const rulesText = question.replace(/^\/rules\s*/i, '').trim();
    if (!rulesText) {
      try {
        const rules = JSON.parse(fs.readFileSync(config.knowledge_dir + '/../rules.json', 'utf8'));
        if (rules.length === 0) return { answer: 'No rules set yet.\n\nUsage: /rules if mentions <keyword> then category=<cat> tags=#tag1 #tag2' };
        const rulesList = rules.map((r, i) => `${i + 1}. If mentions "${r.keyword}" → category: ${r.category}, tags: ${r.tags.join(' ')}`).join('\n');
        return { answer: '📋 Current rules:\n\n' + rulesList + '\n\nTo add: /rules if mentions <keyword> then category=<cat> tags=#tag1 #tag2\nTo clear: /rules clear' };
      } catch(e) { return { answer: 'No rules set yet.\n\nUsage: /rules if mentions <keyword> then category=<cat> tags=#tag1 #tag2' }; }
    }
    if (rulesText === 'clear') { fs.writeFileSync(config.knowledge_dir + '/../rules.json', '[]', 'utf8'); return { answer: '✅ All rules cleared' }; }
    const keywordMatch = rulesText.match(/if mentions ([^\s]+)/i);
    const categoryMatch = rulesText.match(/category=([^\s]+)/i);
    const tagsMatch = rulesText.match(/tags=(#[\w_ #]+)/i) || rulesText.match(/(#[\w_]+(?:\s+#[\w_]+)*)/);
    if (!keywordMatch || !categoryMatch) return { answer: 'Format: /rules if mentions <keyword> then category=<cat> tags=#tag1 #tag2' };
    const newRule = { keyword: keywordMatch[1].toLowerCase(), category: categoryMatch[1].toLowerCase().replace(/[^a-z0-9]/g, ''), tags: tagsMatch ? tagsMatch[1].match(/#[\w_]+/g) || [] : [] };
    let rules = [];
    try { rules = JSON.parse(fs.readFileSync(config.knowledge_dir + '/../rules.json', 'utf8')); } catch(e) {}
    const exists = rules.findIndex(r => r.keyword === newRule.keyword);
    if (exists >= 0) rules[exists] = newRule; else rules.push(newRule);
    fs.writeFileSync(config.knowledge_dir + '/../rules.json', JSON.stringify(rules, null, 2), 'utf8');
    return { answer: '✅ Rule saved: if mentions "' + newRule.keyword + '" → category: ' + newRule.category + ', tags: ' + newRule.tags.join(' ') };
  }

  // /rescan command
  if (question.toLowerCase().startsWith('/rescan')) {
    let rules = [];
    try { rules = JSON.parse(fs.readFileSync(config.knowledge_dir + '/../rules.json', 'utf8')); } catch(e) {}
    if (rules.length === 0) return { answer: '⚠️ No rules set. Add rules first with /rules command.' };
    let updatedCount = 0, movedCount = 0;
    try {
      const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
      for (const file of files) {
        const filepath = config.knowledge_dir + '/' + file;
        let content = fs.readFileSync(filepath, 'utf8');
        const originalContent = content;
        for (const rule of rules) {
          const entries = content.split('---');
          const updatedEntries = entries.map(entry => {
            if (!entry.includes('##')) return entry;
            if (!entry.toLowerCase().includes(rule.keyword)) return entry;
            let updated = entry;
            for (const tag of rule.tags) {
              if (!updated.includes(tag)) { updated = updated.replace(/(\*\*Tags:\*\* [^\n]+)/, '$1 ' + tag); updatedCount++; }
            }
            const currentCategory = file.replace('.md', '');
            if (rule.category !== currentCategory) {
              const targetFilepath = config.knowledge_dir + '/' + rule.category + '.md';
              if (!fs.existsSync(targetFilepath)) fs.writeFileSync(targetFilepath, '# ' + rule.category + '\n', 'utf8');
              fs.appendFileSync(targetFilepath, updated + '---\n', 'utf8');
              movedCount++;
              return null;
            }
            return updated;
          });
          content = updatedEntries.filter(e => e !== null).join('---');
        }
        if (content !== originalContent) fs.writeFileSync(filepath, content, 'utf8');
      }
    } catch(e) { return { answer: '❌ Error during rescan: ' + e.message }; }
    return { answer: `✅ Rescan complete\n\n🏷 Tags updated: ${updatedCount}\n📂 Entries moved: ${movedCount}` };
  }

  // /digest command
  if (question.toLowerCase().startsWith('/digest')) {
    const args = question.replace(/^\/digest\s*/i, '').trim().toLowerCase();
    let settings = { enabled: true, time: '09:00', summary: true, categories: true, voice: true, images: true, stats: true, motivation: true };
    try { settings = { ...settings, ...JSON.parse(fs.readFileSync(config.digest_settings_file, 'utf8')) }; } catch(e) {}
    if (!args) {
      const status = s => s ? '✅ on' : '❌ off';
      return { answer: `⚙️ Daily Digest Settings\n\nEnabled: ${status(settings.enabled)}\nTime: ${settings.time}\n\nSummaries: ${status(settings.summary)}\nGroup by category: ${status(settings.categories)}\nVoice notes: ${status(settings.voice)}\nImages: ${status(settings.images)}\nStats comparison: ${status(settings.stats)}\nMotivation: ${status(settings.motivation)}\n\nCommands:\n/digest on|off\n/digest summary on|off\n/digest categories on|off\n/digest voice on|off\n/digest images on|off\n/digest stats on|off\n/digest motivation on|off\n/digest time HH:MM` };
    }
    const parts = args.split(' ');
    const setting = parts[0];
    const value = parts[1];
    if (setting === 'on') { settings.enabled = true; }
    else if (setting === 'off') { settings.enabled = false; }
    else if (setting === 'time' && value) {
      if (value.match(/^\d{1,2}:\d{2}$/)) { settings.time = value; }
      else return { answer: '❌ Invalid time format. Use HH:MM (e.g. /digest time 08:30)' };
    } else if (['summary','categories','voice','images','stats','motivation'].includes(setting)) {
      if (value === 'on') settings[setting] = true;
      else if (value === 'off') settings[setting] = false;
      else return { answer: '❌ Use on or off. Example: /digest summary on' };
    } else {
      return { answer: '❌ Unknown setting. Send /digest to see all options.' };
    }
    fs.writeFileSync(config.digest_settings_file, JSON.stringify(settings, null, 2), 'utf8');
    const changed = setting === 'on' ? 'Digest enabled' : setting === 'off' ? 'Digest paused' : setting === 'time' ? 'Digest time set to ' + value : setting + ' ' + value;
    return { answer: '✅ ' + changed + '\n\nSend /digest to see all settings.' };
  }

// /help command
if (question.toLowerCase().startsWith('/help')) {
  return { answer: `📖 Available Commands\n\n🔗 *Saving*\nJust send a URL to save it\n/tag <url> #tag1 #tag2 — save with tags\n\n📂 *Browsing*\n/list <category> — list saved links\n\n🏷 *Organization*\n/rules — manage auto-categorization rules\n/rescan — apply rules to all entries\n\n⏰ *Reminders*\nAdd /remind 2weeks to any link when saving\n\n📊 *Digest*\n/digest — configure daily digest\n\n👥 *Guest Access*\n/invite <id> <categories> <duration>\n/guests — list active guests\n/revoke <id> — remove guest\n\n💡 *Tips*\n• Send a voice note to save transcription\n• Send an image to save with AI description\n• Add a note after any URL: https://... this is for kitchen\n• Forward any message with a link to save it` };
}

// /suggest command
if (question.toLowerCase().startsWith('/suggest')) {
  const instruction = question.replace(/^\/suggest\s*/i, '').trim();

  if (!instruction) {
    return { answer: 'Usage: /suggest <your instruction>\n\nExample:\n/suggest anything about AI tools and agents should go to ai category with #agents #tools tags\n/suggest travel links about China should have #china tag\n\nAfter reviewing suggestions, run /suggest apply to apply them.' };
  }

  if (instruction === 'apply') {
    // Apply pending suggestions
    try {
      const pending = JSON.parse(fs.readFileSync(config.knowledge_dir + '/../pending_suggestions.json', 'utf8'));
      if (pending.length === 0) return { answer: 'No pending suggestions to apply.' };
      let appliedCount = 0;
      for (const s of pending) {
        try {
          const filepath = config.knowledge_dir + '/' + s.currentCategory + '.md';
          let content = fs.readFileSync(filepath, 'utf8');
          if (!content.includes(s.url)) continue;
          // Add new tags
          if (s.addTags && s.addTags.length > 0) {
            content = content.replace(
              new RegExp(`(## \\[.+?\\]\\(${s.url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\)[\\s\\S]*?\\*\\*Tags:\\*\\* )([^\\n]+)`),
              (match, prefix, existingTags) => {
                const existing = existingTags.trim();
                const newTags = s.addTags.filter(t => !existing.includes(t)).join(' ');
                return prefix + existing + (newTags ? ' ' + newTags : '');
              }
            );
            fs.writeFileSync(filepath, content, 'utf8');
          }
          // Move to new category
          if (s.newCategory && s.newCategory !== s.currentCategory) {
            const entryMatch = content.match(new RegExp(`\\n## \\[.+?\\]\\(${s.url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\)[\\s\\S]*?---`));
            if (entryMatch) {
              const targetFilepath = config.knowledge_dir + '/' + s.newCategory + '.md';
              if (!fs.existsSync(targetFilepath)) fs.writeFileSync(targetFilepath, '# ' + s.newCategory + '\n', 'utf8');
              fs.appendFileSync(targetFilepath, entryMatch[0] + '\n', 'utf8');
              content = content.replace(entryMatch[0], '');
              fs.writeFileSync(filepath, content, 'utf8');
            }
          }
          appliedCount++;
        } catch(e) {}
      }
      fs.writeFileSync(config.knowledge_dir + '/../pending_suggestions.json', '[]', 'utf8');
      return { answer: '✅ Applied ' + appliedCount + ' suggestions successfully.' };
    } catch(e) {
      return { answer: '❌ No pending suggestions found. Run /suggest <instruction> first.' };
    }
  }

  // Read all entries
  let allEntries = [];
  try {
    const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));
    for (const file of files) {
      const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
      const category = file.replace('.md', '');
      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));
      for (const entry of entries) {
        const titleMatch = entry.match(/## \[(.+?)\]\((.+?)\)/);
        const tagsMatch = entry.match(/\*\*Tags:\*\* ([^\n]+)/);
        const summaryMatch = entry.match(/> (.+)/);
        if (titleMatch) {
          allEntries.push({
            title: titleMatch[1],
            url: titleMatch[2],
            category,
            tags: tagsMatch?.[1] || '',
            summary: summaryMatch?.[1] || ''
          });
        }
      }
    }
  } catch(e) {}

  if (allEntries.length === 0) return { answer: 'No saved entries found.' };

  // Ask Groq to suggest changes
  const suggestResponse = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.groq_api_key },
    body: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0.1,
      messages: [
        { role: 'system', content: 'You are a knowledge organization assistant. Analyze saved entries and suggest categorization changes based on user instructions. Return ONLY a JSON array, no markdown.' },
        { role: 'user', content: 'User instruction: ' + instruction + '\n\nSaved entries:\n' + JSON.stringify(allEntries.slice(0, 50), null, 2) + '\n\nReturn a JSON array of suggested changes. Each item:\n{"title": "...", "url": "...", "currentCategory": "...", "newCategory": "..." or null, "addTags": ["#tag1"] or [], "reason": "short reason"}\n\nOnly include entries that need changes. Return [] if nothing needs changing.' }
      ]
    }
  });

  const raw = suggestResponse.choices?.[0]?.message?.content || '[]';
  let suggestions = [];
  try {
    const match = raw.match(/\[[\s\S]*\]/);
    suggestions = JSON.parse(match ? match[0] : '[]');
  } catch(e) { suggestions = []; }

  if (suggestions.length === 0) {
    return { answer: '✅ No changes needed based on your instruction.' };
  }

  // Save pending suggestions
  fs.writeFileSync(config.knowledge_dir + '/../pending_suggestions.json', JSON.stringify(suggestions, null, 2), 'utf8');

  // Format suggestions for display
  const display = suggestions.slice(0, 10).map((s, i) => {
    let line = `${i + 1}. *${s.title}*`;
    if (s.newCategory && s.newCategory !== s.currentCategory) line += `\n   📂 ${s.currentCategory} → ${s.newCategory}`;
    if (s.addTags && s.addTags.length > 0) line += `\n   🏷 Add: ${s.addTags.join(' ')}`;
    line += `\n   💡 ${s.reason}`;
    return line;
  }).join('\n\n');

  const total = suggestions.length;
  return { answer: `🔍 Found ${total} suggestion${total > 1 ? 's' : ''}:\n\n${display}${total > 10 ? '\n\n...and ' + (total - 10) + ' more' : ''}\n\nSend /suggest apply to apply all changes.` };
}

  // Handle greetings for owner
  const greetings = ['hi','hello','hey','مرحبا','هلا','السلام','صباح','مساء'];
  if (greetings.some(g => question.toLowerCase().startsWith(g))) {
    return { answer: 'أهلاً! أرسل لي رابط لحفظه، أو اسألني عن شيء حفظته سابقاً 👋' };
  }

  // Owner full knowledge query
  const dir = config.knowledge_dir;
  let knowledge = '';
  let fileCount = 0;
  try {
    const files = fs.readdirSync(dir).filter(f => f.endsWith('.md'));
    fileCount = files.length;
    for (const file of files) {
      try {
        const content = fs.readFileSync(dir + '/' + file, 'utf8');
        if (content.trim()) knowledge += '\n\n=== ' + file.replace('.md', '') + ' ===\n' + content.slice(0, 2000);
      } catch(e) {}
    }
  } catch(e) {}
  if (!knowledge.trim()) knowledge = 'No saved links yet.';
  else knowledge = knowledge.slice(0, 20000);

  const groqResponse = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + config.groq_api_key },
    body: { model: 'llama-3.3-70b-versatile', temperature: 0.2, messages: [
      { role: 'system', content: 'You are a personal knowledge assistant. Answer questions using only the saved links provided. Be concise and helpful. For each relevant item include the title and URL. If nothing matches, say so clearly. Respond in the same language as the question.' },
      { role: 'user', content: 'My saved links (' + fileCount + ' categories):\n' + knowledge + '\n\nQuestion: ' + question }
    ]}
  });
  return { answer: groqResponse.choices?.[0]?.message?.content || 'Could not get an answer.' };
}

